/**
 * REVENANT V31-F3 — "Block 3.6: Merchant Verification Validator" (TIER 3)
 * Position: After Intent Extraction (Text Feature Engineering).
 * Upgraded to use a single Vault-backed Merchant Registry.
 */

const items = $input.all();
const returnData = [];

// ---------------------------------------------------------------------------
// MERCHANT REGISTRY (Vault-Backed Consolidation)
// ---------------------------------------------------------------------------
// If Vault is missing, we fall back to the mock to prevent workflow crashes.
const fallbackRegistry = {
  makro: { canonical_id: 'MKR123', status: 'ACTIVE', webhook_endpoint: 'https://pos.makro.uz/api/v1/revenant/notify' },
  korzinka: { canonical_id: 'KRZ456', status: 'ACTIVE', webhook_endpoint: 'https://pos.korzinka.uz/webhooks/revenant' },
  uzum_market: { canonical_id: 'UZM789', status: 'SUSPENDED', webhook_endpoint: 'https://pos.uzum.uz/webhooks/revenant' },
};

let MERCHANT_REGISTRY;
try {
  MERCHANT_REGISTRY = $vars.VAULT_MERCHANT_REGISTRY ? JSON.parse($vars.VAULT_MERCHANT_REGISTRY) : fallbackRegistry;
} catch (e) {
  MERCHANT_REGISTRY = fallbackRegistry;
}

function resolveMerchantAlias(ticket) {
  const structured = ticket.merchant_checkout_request && ticket.merchant_checkout_request.merchant_alias;
  if (structured) return String(structured).toLowerCase();

  const text = `${ticket.subject || ''} ${ticket.body || ''}`.toLowerCase();
  for (const alias of Object.keys(MERCHANT_REGISTRY)) {
    if (text.includes(alias.replace('_', ' ')) || text.includes(alias)) {
      return alias;
    }
  }
  return null;
}

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  if (!ticket) {
    returnData.push(item);
    continue;
  }

  if (ticket.rule_based_intent !== 'MERCHANT_CHECKOUT') {
    returnData.push(item);
    continue;
  }

  const alias = resolveMerchantAlias(ticket);
  const merchant = alias ? MERCHANT_REGISTRY[alias] : null;

  const amount = Number(ticket.transaction_amount);
  const amountValid = Number.isFinite(amount) && amount > 0;

  if (!merchant || merchant.status !== 'ACTIVE' || !amountValid) {
    const errors = [];
    if (!alias || !merchant) errors.push('MERCHANT_NOT_FOUND');
    else if (merchant.status !== 'ACTIVE') errors.push(`MERCHANT_${merchant.status}`);
    if (!amountValid) errors.push('INVALID_CHECKOUT_AMOUNT');

    ticket.ticket_status = 'BLOCKED_INVALID_MERCHANT';
    ticket.block36_passed = false;
    ticket.block36_report = errors.join(', ');
    item.json.canonical_ticket = ticket;
    returnData.push(item);
    continue;
  }

  ticket.merchant_checkout = {
    merchant_alias: alias,
    merchant_id: merchant.canonical_id,
    webhook_endpoint: merchant.webhook_endpoint,
    amount_locked: amount,
    locked_at: new Date().toISOString(),
  };
  ticket.block36_passed = true;
  ticket.block36_report = 'MERCHANT_VERIFICATION_SUCCESS';

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F3 — Merchant Proposal Builder
 * Purpose: Formulates the checkout URL for QR Code generation
 */
const items = $input.all();

for (const item of items) {
  const ticket = item.json.canonical_ticket || {};
  const merchant = ticket.merchant_checkout || {};

  // Extract variables safely
  const amount = merchant.amount_locked || 0;
  const merchantId = merchant.merchant_id || 'UNKNOWN';
  const traceId = ticket.trace_id || 'UNKNOWN_TRACE';

  // Build the dynamic checkout URL for the POS scanner
  // This will feed directly into the next QR Code Generation node
  item.json.qr_target_url = `https://checkout.revenant.bank.uz/pay?merchant=${merchantId}&amount=${amount}&trace=${traceId}`;

  // Update the ticket state
  ticket.proposal_status = 'PROPOSAL_BUILT';
  ticket.proposal_timestamp = new Date().toISOString();

  item.json.canonical_ticket = ticket;
}

return items;

/**
 * REVENANT V31-F3 — "Block 9.8: Merchant POS Notification Builder" (TIER 3)
 * Position: After Core Ledger execution & before Post-Execution Forensic Signer.
 * Upgraded to use the unified Vault-backed Merchant Registry.
 */

const items = $input.all();
const returnData = [];

// ---------------------------------------------------------------------------
// MERCHANT REGISTRY (Vault-Backed Consolidation)
// ---------------------------------------------------------------------------
const fallbackRegistry = {
  MKR123: { webhook_endpoint: 'https://webhook.site/2af49de0-1bde-47dd-9283-b431c9afd463', shared_secret: 'mock_makro_whsec_9a31fe' },
  KRZ456: { webhook_endpoint: 'https://pos.korzinka.uz/webhooks/revenant', shared_secret: 'mock_korzinka_whsec_c218bb' },
  UZM789: { webhook_endpoint: 'https://pos.uzum.uz/webhooks/revenant', shared_secret: 'mock_uzum_whsec_77d4aa' },
};

let MERCHANT_REGISTRY = fallbackRegistry;
try {
  // Translate the unified Vault registry into a canonical_id keyed map for this node
  if ($vars.VAULT_MERCHANT_REGISTRY) {
     const parsed = JSON.parse($vars.VAULT_MERCHANT_REGISTRY);
     MERCHANT_REGISTRY = {};
     for (const key of Object.keys(parsed)) {
         const m = parsed[key];
         if (m.canonical_id) {
             MERCHANT_REGISTRY[m.canonical_id] = {
                 webhook_endpoint: m.webhook_endpoint,
                 shared_secret: m.shared_secret || 'default_secret'
             };
         }
     }
  }
} catch(e) {}

function fnv1a(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

function pureJsHmacSign(payloadString, secret) {
  const inner = fnv1a(secret + payloadString);
  const outer = fnv1a(secret + inner);
  return outer;
}

for (const item of items) {
  const ticket = item.json.canonical_ticket;

  if (!ticket || !ticket.merchant_checkout) {
    returnData.push(item);
    continue;
  }

  const merchantId = ticket.merchant_checkout.merchant_id;
  const merchantConfig = MERCHANT_REGISTRY[merchantId];

  if (!merchantConfig) {
    ticket.block98_passed = false;
    ticket.block98_report = `UNKNOWN_MERCHANT_ID_AT_NOTIFICATION_STAGE: ${merchantId || 'undefined'}`;
    item.json.canonical_ticket = ticket;
    returnData.push(item);
    continue;
  }

  const notificationBody = {
    trace_id: ticket.trace_id,
    amount: ticket.merchant_checkout.amount_locked,
    status: 'SUCCESS',
    timestamp: new Date().toISOString(),
  };

  const signature = pureJsHmacSign(JSON.stringify(notificationBody), merchantConfig.shared_secret);

  item.json.pos_webhook = {
    url: merchantConfig.webhook_endpoint,
    body: notificationBody,
    signature: signature,
  };

  ticket.block98_passed = true;
  ticket.block98_report = 'POS_NOTIFICATION_BUILT';

  delete item.json.__secure_headers;
  for (const key of Object.keys(item.json)) {
    if (/secret|api[_-]?key|auth[_-]?token|password|bearer/i.test(key)) {
      delete item.json[key];
    }
  }

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;
